#include <bits/stdc++.h>using namespace std; int main() {    int N;    cin >> N;    vector<long long> v(N);    for (int i = 0; i < N; i++) {        cin >> v[i];    }     long long health = 0;    priority_queue<long long, vector<long long>, greater<long long>> pq;     for (int i = 0; i < N; i++) {        health += v[i];        pq.push(v[i]);         if (health < 0) {            health -= pq.top();            pq.pop();        }    }     cout << pq.size();    return 0;}